let transfers = {};
try {
    if (typeof msg.payload === 'string' && msg.payload.length > 0) {
        transfers = JSON.parse(msg.payload);
    } else if (msg.payload && typeof msg.payload === 'object') {
        transfers = msg.payload;
    }
} catch (err) {
    node.warn('Failed to parse transfers.json, starting empty: ' + err.message);
    transfers = {};
}
flow.set('transfers', transfers);
node.log('DSP state: ' + Object.keys(transfers).length + ' transfer(s) restored');
return null;

flow.set('transfers', {});
node.log('DSP state: no transfers.json yet — initialised empty map');
return null;

let negotiations = {};
try {
    if (typeof msg.payload === 'string' && msg.payload.length > 0) {
        negotiations = JSON.parse(msg.payload);
    } else if (msg.payload && typeof msg.payload === 'object') {
        negotiations = msg.payload;
    }
} catch (err) {
    node.warn('Failed to parse negotiations.json, starting empty: ' + err.message);
    negotiations = {};
}
flow.set('negotiations', negotiations);
node.log('DSP state: ' + Object.keys(negotiations).length + ' negotiation(s) restored');
return null;

flow.set('negotiations', {});
node.log('DSP state: no negotiations.json yet — initialised empty map');
return null;

// Empty trigger pattern — receiver re-reads the latest snapshot.
// Avoids stale-payload races when two mutations fire near-simultaneously.
const transfers = flow.get('transfers') || {};
return {
    payload: JSON.stringify(transfers, null, 2),
    filename: '/data/dsp-state/transfers.json'
};

const negotiations = flow.get('negotiations') || {};
return {
    payload: JSON.stringify(negotiations, null, 2),
    filename: '/data/dsp-state/negotiations.json'
};
